// ==================== COLORS ====================
const COLORS = {
  bg: '#0a0f1a',
  card: '#111827',
  cardBorder: '#1e293b',
  green: '#10b981',
  blue: '#3b82f6',
  amber: '#f59e0b',
  red: '#ef4444',
  text: '#e5e7eb',
  textMuted: '#9ca3af',
  white: '#ffffff',
};

const RISK_COLORS = { recommended: COLORS.green, low_risk: COLORS.blue, medium_risk: COLORS.amber, high_risk: COLORS.red };
const RISK_LABELS = { recommended: 'Рекомендована', low_risk: 'Низкий риск', medium_risk: 'Средний риск', high_risk: 'Высокий риск' };
const FONT = { fontFamily: '"JetBrains Mono", monospace' };

// ==================== COMPONENTS ====================

function MetricCard({ title, value, subtitle, color }) {
  return (
    <div style={{ background: COLORS.card, border: `1px solid ${COLORS.cardBorder}`, borderRadius: 12, padding: '20px 24px', flex: 1, minWidth: 200 }}>
      <div style={{ color: COLORS.textMuted, fontSize: 13, ...FONT, marginBottom: 8 }}>{title}</div>
      <div style={{ color: color || COLORS.white, fontSize: 28, fontWeight: 700, ...FONT }}>{value}</div>
      {subtitle && <div style={{ color: COLORS.textMuted, fontSize: 12, ...FONT, marginTop: 4 }}>{subtitle}</div>}
    </div>
  );
}

function Badge({ level }) {
  const color = RISK_COLORS[level] || COLORS.textMuted;
  return (
    <span style={{ display: 'inline-block', padding: '2px 10px', borderRadius: 6, background: color + '22', color, fontSize: 12, ...FONT, fontWeight: 600 }}>
      {RISK_LABELS[level] || level}
    </span>
  );
}

function ProgressBar({ value, max, color }) {
  const pct = max > 0 ? (value / max * 100) : 0;
  return (
    <div style={{ background: '#1f2937', borderRadius: 4, height: 8, width: '100%' }}>
      <div style={{ background: color || COLORS.green, borderRadius: 4, height: 8, width: `${Math.min(pct, 100)}%`, transition: 'width 0.3s' }} />
    </div>
  );
}

