// ==================== MAIN APP ====================
const TABS = [
  { id: 'overview', label: 'Обзор' },
  { id: 'regions', label: 'Регионы' },
  { id: 'model', label: 'Модель' },
  { id: 'ranking', label: 'Рейтинг' },
  { id: 'fifo', label: 'FIFO vs Merit' },
];

export default function App() {
  const [activeTab, setActiveTab] = useState('overview');
  return (
    <div style={{ background: COLORS.bg, minHeight: '100vh', color: COLORS.text, ...FONT }}>
      <div style={{ padding: '16px 24px', borderBottom: `1px solid ${COLORS.cardBorder}`, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ color: COLORS.green, fontSize: 20, fontWeight: 700 }}>SubsidyScore AI</span>
          <span style={{ color: COLORS.textMuted, fontSize: 12 }}>Merit-Based Scoring System</span>
        </div>
        <div style={{ color: COLORS.textMuted, fontSize: 12 }}>Decentrathon 5.0 | AI inDrive | Case 2</div>
      </div>
      <div style={{ padding: '0 24px', borderBottom: `1px solid ${COLORS.cardBorder}`, display: 'flex', gap: 0 }}>
        {TABS.map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id)} style={{
            background: 'none', border: 'none', cursor: 'pointer', padding: '12px 20px', ...FONT, fontSize: 13,
            color: activeTab === tab.id ? COLORS.green : COLORS.textMuted,
            borderBottom: activeTab === tab.id ? `2px solid ${COLORS.green}` : '2px solid transparent',
            fontWeight: activeTab === tab.id ? 600 : 400,
          }}>{tab.label}</button>
        ))}
      </div>
      <div style={{ padding: 24, maxWidth: 1200, margin: '0 auto' }}>
        {activeTab === 'overview' && <OverviewTab />}
        {activeTab === 'regions' && <RegionsTab />}
        {activeTab === 'model' && <ModelTab />}
        {activeTab === 'ranking' && <RankingTab />}
        {activeTab === 'fifo' && <FifoMeritTab />}
      </div>
    </div>
  );
}
